#include <iostream>
#include <string>
#include <unordered_map>

std::unordered_map<std::string, std::string> parseURLArguments(const std::string& url)
{
    std::unordered_map<std::string, std::string> dictionary;

    // Check if URL has parameters
    size_t pos = url.find("?");
    if (pos != std::string::npos) {
        std::string params = url.substr(pos + 1);

        // Split parameters by '&'
        size_t start = 0;
        while (start < params.length()) {
            size_t end = params.find("&", start);
            if (end == std::string::npos)
                end = params.length();

            std::string param = params.substr(start, end - start);

            // Split each parameter by '='
            size_t delimiter = param.find("=");
            if (delimiter != std::string::npos) {
                std::string key = param.substr(0, delimiter);
                std::string value = param.substr(delimiter + 1);

                // URL decode the parameter value (optional)
                // Replace '%20' with ' ' (optional)
                size_t percent = value.find("%20");
                while (percent != std::string::npos) {
                    value.replace(percent, 3, " ");
                    percent = value.find("%20", percent + 1);
                }

                dictionary[key] = value;
            }

            start = end + 1;
        }
    }

    return dictionary;
}

int main()
{
    std::string url = "http://www.example.com?name=John%20Doe&age=25&city=New%20York";

    std::unordered_map<std::string, std::string> result = parseURLArguments(url);

    // Print the dictionary
    for (const auto& pair : result) {
        std::cout << pair.first << ": " << pair.second << std::endl;
    }

    return 0;
}
```

