#include <string>

int main() {
    std::string str1 = "";  // Empty string
    std::string str2 = "Hello";

    if (str1.empty()) {
        std::cout << "str1 is empty" << std::endl;
    }
    else {
        std::cout << "str1 is not empty" << std::endl;
    }

    if (str2.empty()) {
        std::cout << "str2 is empty" << std::endl;
    }
    else {
        std::cout << "str2 is not empty" << std::endl;
    }

    return 0;
}
```

Output:
```
str1 is empty
str2 is not empty
```

